import * as XLSX from 'xlsx';

export function sheetToRows(worksheet) {
  const data = XLSX.utils.sheet_to_json(worksheet, { defval: '' });
  return data;
}

export function getRawHeaders(worksheet) {
  const ref = worksheet['!ref'];
  if (!ref) return [];
  const range = XLSX.utils.decode_range(ref);
  const headers = [];
  for (let col = range.s.c; col <= range.e.c; col++) {
    const cell = worksheet[XLSX.utils.encode_cell({ r: range.s.r, c: col })];
    headers.push(cell ? String(cell.v) : '');
  }
  return headers;
}

export function parseWorkbook(data, options = {}) {
  const { codepage } = options;
  const readOpts = { type: 'array', cellDates: true };
  if (codepage) readOpts.codepage = codepage;

  const workbook = XLSX.read(data, readOpts);

  const sheets = workbook.SheetNames.map(name => {
    const ws = workbook.Sheets[name];
    const rawHeaders = getRawHeaders(ws);
    const rows = sheetToRows(ws);
    return { name, rawHeaders, rows };
  });

  return {
    sheetNames: workbook.SheetNames,
    sheets,
  };
}
