import { createImportError } from './import-result.js';
import { HEADER_DICTIONARY } from './header-mapper.js';

const CIRCLED_NUMBER_RE = /^[\u2460-\u2473\u3251-\u325F\u32B1-\u32BF]$/;
const GROUP_LABEL_RE = /^(托盘|Поддон|小计|合计|总计|subtotal|total)/i;

const headerAliasValues = new Set(Object.keys(HEADER_DICTIONARY));

export function isEmptyRow(row) {
  return Object.values(row).every(v => v === '' || v === null || v === undefined || v === 0);
}

export function isGroupedRow(row) {
  const firstVal = String(Object.values(row).find(v => v !== '' && v !== null && v !== undefined) || '').trim();
  if (!firstVal) return false;
  if (CIRCLED_NUMBER_RE.test(firstVal)) return true;
  if (GROUP_LABEL_RE.test(firstVal)) return true;
  return false;
}

export function isRepeatedHeaderRow(row, canonicalHeaders) {
  const values = Object.values(row).map(v => String(v || '').trim());
  const matchCount = values.filter(v => headerAliasValues.has(v) || canonicalHeaders.includes(v)).length;
  return matchCount >= Math.ceil(canonicalHeaders.length * 0.5);
}

function makeError(rowNum, field, message) {
  return createImportError(rowNum, field, message);
}

export function validateProductRow(row, rowNum) {
  const errors = [];
  if (!row.product_code || String(row.product_code).trim() === '') {
    errors.push(makeError(rowNum, 'product_code', 'Product code is required'));
  }
  if (!row.product_name || String(row.product_name).trim() === '') {
    errors.push(makeError(rowNum, 'product_name', 'Product name is required'));
  }
  return errors;
}

export function validateCartonRow(row, rowNum) {
  const errors = [];
  if (!row.product_code || String(row.product_code).trim() === '') {
    errors.push(makeError(rowNum, 'product_code', 'Product code is required'));
  }
  if (typeof row.outer_length_mm !== 'number' || row.outer_length_mm <= 0) {
    errors.push(makeError(rowNum, 'outer_length_mm', 'Length must be positive (mm)'));
  }
  if (typeof row.outer_width_mm !== 'number' || row.outer_width_mm <= 0) {
    errors.push(makeError(rowNum, 'outer_width_mm', 'Width must be positive (mm)'));
  }
  if (typeof row.outer_height_mm !== 'number' || row.outer_height_mm <= 0) {
    errors.push(makeError(rowNum, 'outer_height_mm', 'Height must be positive (mm)'));
  }
  if (typeof row.carton_count !== 'number' || row.carton_count <= 0) {
    errors.push(makeError(rowNum, 'carton_count', 'Carton count must be positive'));
  }
  return errors;
}

export function validateDemandRow(row, rowNum) {
  const errors = [];
  if (!row.product_code || String(row.product_code).trim() === '') {
    errors.push(makeError(rowNum, 'product_code', 'Product code is required'));
  }
  const hasQty = (typeof row.requested_qty === 'number' && row.requested_qty > 0)
    || (typeof row.actual_required_qty === 'number' && row.actual_required_qty > 0)
    || (typeof row.warehouse_total_qty === 'number' && row.warehouse_total_qty > 0);
  if (!hasQty) {
    errors.push(makeError(rowNum, 'qty', 'At least one quantity field must be positive'));
  }
  return errors;
}

export function validatePalletRow(row, rowNum) {
  const errors = [];
  if (typeof row.pallet_length_mm !== 'number' || row.pallet_length_mm <= 0) {
    errors.push(makeError(rowNum, 'pallet_length_mm', 'Pallet length must be positive (mm)'));
  }
  if (typeof row.pallet_width_mm !== 'number' || row.pallet_width_mm <= 0) {
    errors.push(makeError(rowNum, 'pallet_width_mm', 'Pallet width must be positive (mm)'));
  }
  if (typeof row.pallet_height_mm !== 'number' || row.pallet_height_mm <= 0) {
    errors.push(makeError(rowNum, 'pallet_height_mm', 'Pallet height must be positive (mm)'));
  }
  return errors;
}

const VALIDATORS = {
  product: validateProductRow,
  carton: validateCartonRow,
  demand: validateDemandRow,
  pallet: validatePalletRow,
};

export function filterAndValidateRows(rows, sheetType, canonicalHeaders) {
  const validRows = [];
  const allErrors = [];
  let skippedCount = 0;

  const validate = VALIDATORS[sheetType] || (() => []);

  for (let i = 0; i < rows.length; i++) {
    const rowNum = i + 2;
    const row = rows[i];

    if (isEmptyRow(row)) { skippedCount++; continue; }
    if (isGroupedRow(row)) { skippedCount++; continue; }
    if (isRepeatedHeaderRow(row, canonicalHeaders)) { skippedCount++; continue; }

    const errors = validate(row, rowNum);
    if (errors.length > 0) {
      allErrors.push(...errors);
    } else {
      validRows.push(row);
    }
  }

  return { validRows, errors: allErrors, skippedCount };
}
