export const SHEET_FINGERPRINTS = Object.freeze({
  pallet: {
    required: ['pallet_length_mm', 'pallet_width_mm', 'pallet_height_mm'],
    bonus: ['pallet_weight_kg', 'pallet_no', 'pallet_code', 'pallet_volume_m3'],
  },
  carton: {
    required: ['outer_length_mm', 'outer_width_mm', 'outer_height_mm', 'carton_count'],
    bonus: ['gross_weight_kg', 'net_weight_kg', 'volume_m3', 'heavy_cargo_flag', 'rotation_allowed'],
  },
  demand: {
    required: ['product_code'],
    requiredAny: ['requested_qty', 'actual_required_qty', 'warehouse_total_qty'],
    bonus: ['carton_pack_size', 'actual_carton_count', 'tail_qty', 'warehouse_full_carton_qty'],
  },
  product: {
    required: ['product_code', 'product_name'],
    bonus: ['product_version', 'remarks'],
  },
});

export function detectSheetType(canonicalHeaders) {
  const headerSet = new Set(canonicalHeaders);
  let bestType = 'unknown';
  let bestScore = 0;

  for (const [type, fp] of Object.entries(SHEET_FINGERPRINTS)) {
    const requiredMet = (fp.required || []).every(f => headerSet.has(f));
    if (!requiredMet) continue;

    if (fp.requiredAny && !fp.requiredAny.some(f => headerSet.has(f))) continue;

    let score = (fp.required || []).length;
    if (fp.requiredAny) {
      score += fp.requiredAny.filter(f => headerSet.has(f)).length;
    }
    score += 0.5 * (fp.bonus || []).filter(f => headerSet.has(f)).length;

    if (score > bestScore) {
      bestScore = score;
      bestType = type;
    }
  }

  return bestType;
}
