export function createImportError(row, field, message) {
  return Object.freeze({ row, field, message });
}

export function createSheetResult(sheetName, sheetType, rows, errors) {
  return Object.freeze({
    sheetName,
    sheetType,
    rows: Object.freeze([...rows]),
    errors: Object.freeze([...errors]),
    rowCount: rows.length,
    errorCount: errors.length,
  });
}

export function createImportResult(sheetResults, products, demandLines, cartons, pallets) {
  const allErrors = sheetResults.flatMap(s => s.errors);
  return Object.freeze({
    sheetResults: Object.freeze(sheetResults.map(s => Object.freeze({ ...s }))),
    products: Object.freeze([...products]),
    demandLines: Object.freeze([...demandLines]),
    cartons: Object.freeze([...cartons]),
    pallets: Object.freeze([...pallets]),
    totalErrors: allErrors.length,
    errors: Object.freeze([...allErrors]),
    summary: Object.freeze({
      sheetsProcessed: sheetResults.length,
      productsFound: products.length,
      demandLinesFound: demandLines.length,
      cartonsFound: cartons.length,
      palletsFound: pallets.length,
      errorsFound: allErrors.length,
    }),
  });
}
