import { parseWorkbook } from './workbook-reader.js';
import { mapHeaders } from './header-mapper.js';
import { sanitizeRow } from './sanitizer.js';
import { normalizeRow } from './row-normalizer.js';
import { detectSheetType } from './sheet-detector.js';
import { filterAndValidateRows } from './import-validator.js';
import { createImportResult, createSheetResult } from './import-result.js';
import { registerAdapter, findAdapter, clearAdapters } from './adapters/base-adapter.js';
import { sample1Adapter } from './adapters/sample1-adapter.js';
import { sample2Adapter } from './adapters/sample2-adapter.js';
import { detectDimensionUnit } from './dimension-unit.js';

export function initAdapters() {
  clearAdapters();
  registerAdapter(sample1Adapter);
  registerAdapter(sample2Adapter);
}

export function importWorkbook(data, options = {}) {
  const { sheets } = parseWorkbook(data, options);

  const processedSheets = sheets.map(sheet => {
    const { headers: canonicalHeaders, coverage, unmapped } = mapHeaders(sheet.rawHeaders, { returnCoverage: true });

    const remappedRows = sheet.rows.map(row => {
      const newRow = {};
      const rawKeys = Object.keys(row);
      for (let i = 0; i < rawKeys.length; i++) {
        const mappedKey = i < canonicalHeaders.length ? canonicalHeaders[i] : rawKeys[i];
        const canonicalKey = mappedKey && String(mappedKey).trim() !== '' ? mappedKey : rawKeys[i];
        newRow[canonicalKey] = row[rawKeys[i]];
      }
      return newRow;
    });

    const sanitizedRows = remappedRows.map(sanitizeRow);
    const normalizedRows = sanitizedRows.map(normalizeRow);
    let detectedType = detectSheetType(canonicalHeaders);

    const DEMAND_QTY_FIELDS = ['requested_qty', 'actual_required_qty', 'warehouse_total_qty'];
    if (detectedType === 'carton' && DEMAND_QTY_FIELDS.some(f => canonicalHeaders.includes(f))) {
      detectedType = 'demand';
    }

    const { validRows, errors, skippedCount } = filterAndValidateRows(normalizedRows, detectedType, canonicalHeaders);

    return {
      name: sheet.name,
      detectedType,
      canonicalHeaders,
      coverage,
      unmapped,
      validRows,
      errors,
      skippedCount,
    };
  });

  const adapter = findAdapter(processedSheets);

  if (!adapter) {
    const sheetResults = processedSheets.map(s => createSheetResult(s.name, s.detectedType, s.validRows, s.errors));
    return createImportResult(sheetResults, [], [], [], []);
  }

  const extracted = adapter.extract(processedSheets);
  const sheetResults = processedSheets.map(s => createSheetResult(s.name, s.detectedType, s.validRows, s.errors));

  const importResult = createImportResult(
    sheetResults,
    extracted.products || [],
    extracted.demandLines || [],
    extracted.cartons || [],
    extracted.pallets || [],
  );

  return Object.freeze({
    ...importResult,
    dimensionUnit: detectDimensionUnit(extracted.cartons || []),
  });
}
