const DIMENSION_RE = /^\s*([\d.]+)\s*[*×xX]\s*([\d.]+)\s*[*×xX]\s*([\d.]+)\s*$/;

export function parseDimensions(value) {
  if (value === null || value === undefined) return null;
  const str = String(value).trim();
  const match = str.match(DIMENSION_RE);
  if (!match) return null;
  const [, l, w, h] = match;
  return { length: parseFloat(l), width: parseFloat(w), height: parseFloat(h) };
}

export function coerceNumber(value, defaultValue = null) {
  if (typeof value === 'number' && isFinite(value)) return value;
  if (value === null || value === undefined || value === '') return defaultValue;
  const num = Number(value);
  return isFinite(num) ? num : defaultValue;
}

const TRUE_VALUES = new Set(['是', 'yes', 'y', '1', 'true']);
const FALSE_VALUES = new Set(['否', 'no', 'n', '0', 'false']);

export function normalizeBoolean(value, defaultValue = false) {
  if (typeof value === 'boolean') return value;
  if (value === 1 || value === true) return true;
  if (value === 0 || value === false) return false;
  if (value === null || value === undefined) return defaultValue;
  const str = String(value).trim().toLowerCase();
  if (TRUE_VALUES.has(str)) return true;
  if (FALSE_VALUES.has(str)) return false;
  return defaultValue;
}

const MAX4_PATTERNS = new Set(['max4', '仅1-4层', '1-4']);

export function normalizeLayerRule(value) {
  if (value === null || value === undefined || value === '') return 'none';
  const str = String(value).trim().toLowerCase();
  if (MAX4_PATTERNS.has(str)) return 'max4';
  if (FALSE_VALUES.has(str)) return 'none';
  return 'none';
}

const NUMERIC_FIELDS = new Set([
  'outer_length_mm', 'outer_width_mm', 'outer_height_mm',
  'gross_weight_kg', 'net_weight_kg', 'total_gross_weight_kg', 'total_net_weight_kg',
  'volume_m3', 'carton_count', 'actual_carton_count', 'carton_pack_size',
  'requested_qty', 'actual_required_qty', 'warehouse_full_carton_qty',
  'tail_qty', 'warehouse_total_qty',
  'pallet_length_mm', 'pallet_width_mm', 'pallet_height_mm',
  'pallet_volume_m3', 'pallet_weight_kg',
]);

const BOOLEAN_FIELDS = new Set(['heavy_cargo_flag', 'rotation_allowed', 'mix_allowed']);

export function normalizeRow(row) {
  const result = { ...row };
  if (result.outer_dimensions_mm && !result.outer_length_mm) {
    const dims = parseDimensions(result.outer_dimensions_mm);
    if (dims) {
      result.outer_length_mm = dims.length;
      result.outer_width_mm = dims.width;
      result.outer_height_mm = dims.height;
    }
    delete result.outer_dimensions_mm;
  }
  for (const field of NUMERIC_FIELDS) {
    if (field in result) {
      result[field] = coerceNumber(result[field], 0);
    }
  }
  for (const field of BOOLEAN_FIELDS) {
    if (field in result) {
      result[field] = normalizeBoolean(result[field], false);
    }
  }
  if ('stack_limit_rule' in result) {
    result.stack_limit_rule = normalizeLayerRule(result.stack_limit_rule);
  }
  return result;
}
