export const sample1Adapter = {
  name: 'sample1',

  canHandle(sheets) {
    const hasPallet = sheets.some(s => s.detectedType === 'pallet');
    const hasCarton = sheets.some(s => s.detectedType === 'carton');
    return hasPallet && hasCarton;
  },

  extract(sheets) {
    const products = [];
    const demandLines = [];
    const cartons = [];
    const pallets = [];

    for (const sheet of sheets) {
      if (sheet.detectedType === 'carton') {
        for (const row of sheet.validRows) {
          cartons.push({ ...row, source_sheet: sheet.name });
        }
      }
      if (sheet.detectedType === 'pallet') {
        for (const row of sheet.validRows) {
          pallets.push({ ...row, source_sheet: sheet.name });
        }
      }
      if (sheet.detectedType === 'product') {
        for (const row of sheet.validRows) {
          products.push({ ...row, source_sheet: sheet.name });
        }
      }
      if (sheet.detectedType === 'demand') {
        for (const row of sheet.validRows) {
          demandLines.push({ ...row, source_sheet: sheet.name });
        }
      }
    }

    return { products, demandLines, cartons, pallets };
  },
};
