// src/import/adapters/base-adapter.js

const adapters = [];

export function registerAdapter(adapter) {
  if (typeof adapter.name !== 'string') throw new Error('Adapter must have a name');
  if (typeof adapter.canHandle !== 'function') throw new Error('Adapter must implement canHandle(sheets)');
  if (typeof adapter.extract !== 'function') throw new Error('Adapter must implement extract(sheets)');
  adapters.push(adapter);
}

export function findAdapter(sheets) {
  for (const adapter of adapters) {
    if (adapter.canHandle(sheets)) return adapter;
  }
  return null;
}

export function getRegisteredAdapters() {
  return [...adapters];
}

export function clearAdapters() {
  adapters.length = 0;
}
