export const HEADER_DICTIONARY = Object.freeze({
  // Product fields — Chinese
  '产品编码': 'product_code',
  '产品型号': 'product_code',
  '产品版本号': 'product_version',
  '产品名称': 'product_name',
  // Product fields — Russian
  'Артикул': 'product_code',
  'Код версии': 'product_version',
  'Наименование': 'product_name',
  // Demand fields — Chinese
  '需求数量': 'requested_qty',
  '实际需求': 'actual_required_qty',
  '实际数量': 'actual_required_qty',
  '箱规': 'carton_pack_size',
  '箱规数量': 'carton_pack_size',
  '箱数': 'carton_count',
  '实际箱数': 'actual_carton_count',
  '尾数': 'tail_qty',
  // Warehouse fields — Chinese (including newline variants)
  '仓库实际数量（整箱）': 'warehouse_full_carton_qty',
  '仓库实际数\n量（整箱）': 'warehouse_full_carton_qty',
  '仓库总共数量': 'warehouse_total_qty',
  // Dimension fields — Chinese
  '外箱长': 'outer_length_mm',
  '外箱宽': 'outer_width_mm',
  '外箱高': 'outer_height_mm',
  '外箱尺寸（mm）': 'outer_dimensions_mm',
  '单箱尺寸（L*W*H/mm）': 'outer_dimensions_mm',
  // Weight fields — Chinese
  '重量': 'gross_weight_kg',
  '单箱毛重': 'gross_weight_kg',
  '单箱净重': 'net_weight_kg',
  '产品毛重（KG）/箱': 'gross_weight_kg',
  '产品净重（KG)/个': 'net_weight_kg',
  '产品净重\n（KG)/个': 'net_weight_kg',
  '产品总毛重': 'total_gross_weight_kg',
  '产品总净重': 'total_net_weight_kg',
  // Volume
  '单箱体积': 'volume_m3',
  // Carton flags — Chinese
  '是否重货': 'heavy_cargo_flag',
  '层限制': 'stack_limit_rule',
  '是否允许侧放': 'rotation_allowed',
  // Pallet fields — Chinese
  '整托尺寸': 'pallet_dimensions',
  '整托长': 'pallet_length_mm',
  '整托宽': 'pallet_width_mm',
  '整托高': 'pallet_height_mm',
  '整托体积': 'pallet_volume_m3',
  '整托重量': 'pallet_weight_kg',
  '托盘编号': 'pallet_no',
  '托盘代码': 'pallet_code',
  // Source tracking
  '备注': 'remarks',
});

/**
 * Maps raw headers to canonical field names using HEADER_DICTIONARY.
 * Handles: exact match, trimmed match, newline-in-header match, and already-canonical passthrough.
 *
 * @param {string[]} rawHeaders - Array of raw header strings
 * @param {Object} options - Optional configuration
 * @param {boolean} options.returnCoverage - If true, return object with headers, coverage, and unmapped
 * @returns {string[] | Object} Mapped headers array, or object with coverage info if returnCoverage is true
 */
export function mapHeaders(rawHeaders, options = {}) {
  const mapped = [];
  const unmapped = [];
  const canonicalNames = new Set(Object.values(HEADER_DICTIONARY));

  for (const rawHeader of rawHeaders) {
    // 1. Exact match in HEADER_DICTIONARY
    if (rawHeader in HEADER_DICTIONARY) {
      mapped.push(HEADER_DICTIONARY[rawHeader]);
      continue;
    }

    // 2. Normalized match (collapse newlines/whitespace to single space, trim)
    const normalized = rawHeader.replace(/\s+/g, ' ').trim();
    if (normalized in HEADER_DICTIONARY) {
      mapped.push(HEADER_DICTIONARY[normalized]);
      continue;
    }

    // 3. Already a canonical English name → passthrough
    if (canonicalNames.has(rawHeader)) {
      mapped.push(rawHeader);
      continue;
    }

    // 4. No match → keep original
    mapped.push(rawHeader);
    unmapped.push(rawHeader);
  }

  if (options.returnCoverage) {
    const coverage = rawHeaders.length > 0 ? (rawHeaders.length - unmapped.length) / rawHeaders.length : 0;
    return {
      headers: mapped,
      coverage,
      unmapped,
    };
  }

  return mapped;
}
