const WAREHOUSE_FIELDS = ['warehouse_full_carton_qty', 'tail_qty', 'warehouse_total_qty'];
const INLINE_CARTON_FIELDS = ['carton_count', 'actual_carton_count', 'outer_length_mm', 'outer_width_mm', 'outer_height_mm'];

export const sample2Adapter = {
  name: 'sample2',

  canHandle(sheets) {
    return sheets.some((sheet) => {
      if (sheet.detectedType !== 'demand') return false;
      const headers = Array.isArray(sheet.canonicalHeaders) ? sheet.canonicalHeaders : [];
      return WAREHOUSE_FIELDS.some((field) => headers.includes(field))
        || INLINE_CARTON_FIELDS.some((field) => headers.includes(field));
    });
  },

  extract(sheets) {
    const products = [];
    const demandLines = [];
    const cartons = [];
    const pallets = [];

    for (const sheet of sheets) {
      if (sheet.detectedType === 'demand') {
        for (const row of sheet.validRows) {
          demandLines.push({ ...row, source_sheet: sheet.name });

          const hasDims = row.outer_length_mm > 0 && row.outer_width_mm > 0 && row.outer_height_mm > 0;
          if (hasDims) {
            cartons.push({
              product_code: row.product_code,
              outer_length_mm: row.outer_length_mm,
              outer_width_mm: row.outer_width_mm,
              outer_height_mm: row.outer_height_mm,
              gross_weight_kg: row.gross_weight_kg || 0,
              net_weight_kg: row.net_weight_kg || 0,
              carton_count: row.carton_count || row.actual_carton_count || 0,
              actual_carton_count: row.actual_carton_count || 0,
              requested_carton_count: row.requested_carton_count || 0,
              carton_pack_size: row.carton_pack_size || 0,
              requested_qty: row.requested_qty || 0,
              actual_required_qty: row.actual_required_qty || 0,
              warehouse_total_qty: row.warehouse_total_qty || 0,
              source_sheet: sheet.name,
            });
          }
        }
      }
      if (sheet.detectedType === 'product') {
        for (const row of sheet.validRows) {
          products.push({ ...row, source_sheet: sheet.name });
        }
      }
      if (sheet.detectedType === 'pallet') {
        for (const row of sheet.validRows) {
          pallets.push({ ...row, source_sheet: sheet.name });
        }
      }
    }

    return { products, demandLines, cartons, pallets };
  },
};
